const express = require('express');
const http = require('http');
const https = require('https');
const axios = require('axios');
const vm = require('vm');
const fs = require('fs');
const path = require('path');

class PluginManager {
  constructor() {
    this.plugins = [];
  }

  loadPluginFromCode(code, pluginName = 'anonymous') {
    try {
      const sandbox = {
        console,
        require,
        module: { exports: {} },
        exports: {},
        Buffer,
        setTimeout,
        setInterval,
        clearTimeout,
        clearInterval,
        process: {
          env: process.env,
          nextTick: process.nextTick
        }
      };

      vm.createContext(sandbox);
      vm.runInContext(code, sandbox);

      const plugin = sandbox.module.exports || sandbox.exports;
      
      if (typeof plugin === 'function') {
        this.plugins.push({ name: pluginName, handler: plugin });
      } else if (typeof plugin === 'object' && plugin.handler) {
        this.plugins.push({ name: pluginName, ...plugin });
      } else {
        throw new Error('Plugin must export a function or object with handler property');
      }

      return true;
    } catch (error) {
      console.error(`Failed to load plugin ${pluginName}:`, error);
      return false;
    }
  }

  loadPluginFromFile(filePath) {
    try {
      const absolutePath = path.resolve(filePath);
      const pluginName = path.basename(filePath, path.extname(filePath));
      
      delete require.cache[require.resolve(absolutePath)];
      const plugin = require(absolutePath);

      if (typeof plugin === 'function') {
        this.plugins.push({ name: pluginName, handler: plugin });
      } else if (typeof plugin === 'object' && plugin.handler) {
        this.plugins.push({ name: pluginName, ...plugin });
      } else {
        throw new Error('Plugin must export a function or object with handler property');
      }

      return true;
    } catch (error) {
      console.error(`Failed to load plugin from file ${filePath}:`, error);
      return false;
    }
  }

  loadPluginFromEnv(envVar) {
    const code = process.env[envVar];
    if (code) {
      return this.loadPluginFromCode(code, `env_${envVar}`);
    }
    return false;
  }

  loadPluginFromEval(code, pluginName = 'eval_plugin') {
    try {
      const plugin = eval(`(${code})`);
      
      if (typeof plugin === 'function') {
        this.plugins.push({ name: pluginName, handler: plugin });
      } else if (typeof plugin === 'object' && plugin.handler) {
        this.plugins.push({ name: pluginName, ...plugin });
      } else {
        throw new Error('Plugin must be a function or object with handler property');
      }

      return true;
    } catch (error) {
      console.error(`Failed to load plugin ${pluginName}:`, error);
      return false;
    }
  }

  async executePlugins(stage, context) {
    for (const plugin of this.plugins) {
      try {
        if (plugin.stage && plugin.stage !== stage) {
          continue;
        }

        const handler = plugin.handler || plugin;
        
        if (typeof handler === 'function') {
          const result = await handler(context, stage);
          
          if (result === false) {
            return false;
          }
          
          if (result && typeof result === 'object') {
            Object.assign(context, result);
          }
        }
      } catch (error) {
        console.error(`Plugin ${plugin.name} error:`, error);
        if (plugin.critical) {
          throw error;
        }
      }
    }
    return true;
  }
}

class APIGateway {
  constructor(config = {}) {
    this.app = express();
    this.config = config;
    this.pluginManager = new PluginManager();
    this.routes = config.routes || [];
    
    this.setupMiddleware();
    this.loadPlugins();
    this.setupRoutes();
  }

  setupMiddleware() {
    this.app.use(express.json({ limit: '10mb' }));
    this.app.use(express.urlencoded({ extended: true, limit: '10mb' }));
  }

  loadPlugins() {
    const pluginConfig = this.config.plugins || {};

    if (pluginConfig.files && Array.isArray(pluginConfig.files)) {
      pluginConfig.files.forEach(filePath => {
        this.pluginManager.loadPluginFromFile(filePath);
      });
    }

    if (pluginConfig.code && Array.isArray(pluginConfig.code)) {
      pluginConfig.code.forEach((codeObj, index) => {
        const name = codeObj.name || `inline_${index}`;
        this.pluginManager.loadPluginFromCode(codeObj.code, name);
      });
    }

    if (pluginConfig.env && Array.isArray(pluginConfig.env)) {
      pluginConfig.env.forEach(envVar => {
        this.pluginManager.loadPluginFromEnv(envVar);
      });
    }

    if (pluginConfig.eval && Array.isArray(pluginConfig.eval)) {
      pluginConfig.eval.forEach((evalObj, index) => {
        const name = evalObj.name || `eval_${index}`;
        this.pluginManager.loadPluginFromEval(evalObj.code, name);
      });
    }

    if (pluginConfig.dynamic) {
      Object.keys(pluginConfig.dynamic).forEach(name => {
        const code = pluginConfig.dynamic[name];
        this.pluginManager.loadPluginFromCode(code, name);
      });
    }
  }

  setupRoutes() {
    this.app.all('*', async (req, res) => {
      try {
        const context = {
          request: {
            method: req.method,
            path: req.path,
            headers: req.headers,
            query: req.query,
            body: req.body,
            params: req.params
          },
          response: {
            statusCode: 200,
            headers: {},
            body: null
          },
          state: {},
          targetUrl: null,
          shouldProxy: true
        };

        const continueExecution = await this.pluginManager.executePlugins('preRequest', context);
        
        if (!continueExecution) {
          return this.sendResponse(res, context.response);
        }

        const route = this.findRoute(context.request.path, context.request.method);
        
        if (route) {
          context.targetUrl = this.buildTargetUrl(route, context.request);
        } else if (this.config.defaultTarget) {
          context.targetUrl = this.buildDefaultTargetUrl(context.request);
        }

        await this.pluginManager.executePlugins('preProxy', context);

        if (context.shouldProxy && context.targetUrl) {
          try {
            const proxyResponse = await this.proxyRequest(context);
            context.response.statusCode = proxyResponse.status;
            context.response.headers = proxyResponse.headers;
            context.response.body = proxyResponse.data;
          } catch (error) {
            context.response.statusCode = error.response?.status || 502;
            context.response.body = {
              error: 'Proxy error',
              message: error.message
            };
          }
        }

        await this.pluginManager.executePlugins('postProxy', context);

        this.sendResponse(res, context.response);

        await this.pluginManager.executePlugins('postResponse', context);

      } catch (error) {
        console.error('Gateway error:', error);
        res.status(500).json({
          error: 'Internal gateway error',
          message: error.message
        });
      }
    });
  }

  findRoute(path, method) {
    return this.routes.find(route => {
      const pathMatch = route.path === path || 
                       (route.pathPattern && new RegExp(route.pathPattern).test(path));
      const methodMatch = !route.method || route.method === method;
      return pathMatch && methodMatch;
    });
  }

  buildTargetUrl(route, request) {
    let url = route.target;
    
    if (route.appendPath) {
      url += request.path;
    }

    const queryString = new URLSearchParams(request.query).toString();
    if (queryString) {
      url += (url.includes('?') ? '&' : '?') + queryString;
    }

    return url;
  }

  buildDefaultTargetUrl(request) {
    let url = this.config.defaultTarget + request.path;
    const queryString = new URLSearchParams(request.query).toString();
    if (queryString) {
      url += '?' + queryString;
    }
    return url;
  }

  async proxyRequest(context) {
    const options = {
      method: context.request.method,
      url: context.targetUrl,
      headers: { ...context.request.headers },
      validateStatus: () => true
    };

    delete options.headers['host'];
    delete options.headers['content-length'];

    if (context.request.body && Object.keys(context.request.body).length > 0) {
      options.data = context.request.body;
    }

    return await axios(options);
  }

  sendResponse(res, response) {
    res.status(response.statusCode);
    
    Object.keys(response.headers).forEach(key => {
      res.setHeader(key, response.headers[key]);
    });

    if (response.body !== null && response.body !== undefined) {
      if (typeof response.body === 'object') {
        res.json(response.body);
      } else {
        res.send(response.body);
      }
    } else {
      res.end();
    }
  }

  addPlugin(code, name) {
    return this.pluginManager.loadPluginFromCode(code, name);
  }

  start(port = 3000) {
    this.app.listen(port, () => {
      console.log(`API Gateway running on port ${port}`);
      console.log(`Loaded ${this.pluginManager.plugins.length} plugins`);
    });
  }
}

const defaultConfig = {
  routes: [
    {
      path: '/api/users',
      target: 'http://localhost:4000/users',
      method: 'GET'
    }
  ],
  defaultTarget: 'http://localhost:4000',
  plugins: {
    files: [],
    code: [],
    env: [],
    eval: [],
    dynamic: {}
  }
};

let config = defaultConfig;

if (fs.existsSync('./gateway-config.json')) {
  const fileConfig = JSON.parse(fs.readFileSync('./gateway-config.json', 'utf8'));
  config = { ...defaultConfig, ...fileConfig };
}

if (process.env.GATEWAY_CONFIG) {
  try {
    const envConfig = JSON.parse(process.env.GATEWAY_CONFIG);
    config = { ...config, ...envConfig };
  } catch (e) {
    console.error('Failed to parse GATEWAY_CONFIG:', e);
  }
}

const gateway = new APIGateway(config);

gateway.start(process.env.PORT || 3000);

module.exports = { APIGateway, PluginManager };